def rel(path: Path) -> str:
    return str(path.relative_to(ROOT))


def check_required_paths(errors: list[str]) -> None:
    for path in REQUIRED_PATHS:
        if not (ROOT / path).exists():
            errors.append(f"missing required path: {path}")


def check_root_markdown(errors: list[str]) -> None:
    allowed = {"README.md", "AGENTS.md"}
    found = {path.name for path in ROOT.glob("*.md")}
    extra = sorted(found - allowed)
    if extra:
        errors.append(f"unexpected root markdown files: {', '.join(extra)}")


def check_forbidden_paths(errors: list[str]) -> None:
    if (ROOT / "docs/plan").exists():
        errors.append("forbidden path exists: docs/plan")


def check_plan_names(errors: list[str]) -> None:
    for directory in [
        ROOT / "docs/exec_plans/active",
        ROOT / "docs/exec_plans/completed",
    ]:
        if not directory.exists():
            continue
        for path in directory.glob("*.md"):
            if not PLAN_RE.fullmatch(path.name):
                errors.append(f"invalid plan filename: {rel(path)}")


def check_text_expectations(errors: list[str]) -> None:
    for file_path, needles in TEXT_EXPECTATIONS.items():
        text = (ROOT / file_path).read_text(encoding="utf-8")
        for needle in needles:
            if needle not in text:
                errors.append(f"{file_path} missing text: {needle}")


def check_official_sources(errors: list[str]) -> None:
    text = (ROOT / "docs/references/official-sources.md").read_text(encoding="utf-8")
    if "| TODO |" in text:
        errors.append("official sources still contain placeholder table rows")


def check_strict_todos(errors: list[str]) -> None:
    ignored_prefixes = {
        ".worktree/",
        "dist/",
        "dist-electron/",
        "harness/templates/",
        "node_modules/",
    }
    for path in ROOT.rglob("*.md"):
        relative = rel(path)
        if any(relative.startswith(prefix) for prefix in ignored_prefixes):
            continue
        text = path.read_text(encoding="utf-8")
        if "TODO" in text:
            errors.append(f"strict mode found TODO in {relative}")


def check_offline_render_determinism(errors: list[str]) -> None:
    render_text = (ROOT / "src/audio/render.ts").read_text(encoding="utf-8")
    if "Math.random" in render_text:
        errors.append("src/audio/render.ts must not use Math.random in the offline render path")


def check_build_chunk_config(errors: list[str]) -> None:
    vite_text = (ROOT / "vite.config.ts").read_text(encoding="utf-8")
    if "chunkSizeWarningLimit" in vite_text:
        errors.append("vite.config.ts must use real chunk splitting instead of chunkSizeWarningLimit")


def check_domain_sampling_boundaries(errors: list[str]) -> None:
    domain_text = (ROOT / "src/domain/workstation.ts").read_text(encoding="utf-8")
    track_type_match = re.search(r"export type TrackType\s*=([^;]+);", domain_text, re.S)
    if not track_type_match:
        errors.append("src/domain/workstation.ts must define the core TrackType union")
        return

    track_type_union = track_type_match.group(1)
    if re.search(r'"(?:audio|sampler)"', track_type_union):
        errors.append("core TrackType union must not include audio or sampler before optional sampling-phase work")
    if "AudioClipEvent" in domain_text:
        errors.append("core domain model must not include AudioClipEvent before optional sampling-phase work")


def run_checks(strict: bool = False) -> list[str]:
    errors: list[str] = []
    check_required_paths(errors)
    check_root_markdown(errors)
    check_forbidden_paths(errors)
    check_plan_names(errors)
    check_text_expectations(errors)
    check_official_sources(errors)
    check_offline_render_determinism(errors)
    check_build_chunk_config(errors)
    check_domain_sampling_boundaries(errors)
    if strict:
        check_strict_todos(errors)
    return errors


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description="Validate the GrooveForge project base.")
    parser.add_argument("--strict", action="store_true", help="Fail on TODO markers outside templates.")
    args = parser.parse_args(argv)

    errors = run_checks(strict=args.strict)
    if errors:
        print("QA failed:")
        for error in errors:
            print(f"- {error}")
        return 1

    mode = "strict " if args.strict else ""
    print(f"GrooveForge {mode}QA passed.")
    return 0


if __name__ == "__main__":
    sys.exit(main())
